90	pub fn run(paths: &[String], config: &Config) -> RunResult {
91	    let exclude_set = match build_glob_set(&config.excludes) {
92	        Ok(gs) => gs,
93	        Err(e) => return RunResult::Error(format!("invalid exclude glob: {}", e)),
94	    };
95	
96	    let (functions, errors) = collect_all_functions(paths, &exclude_set);
97	
98	    if !errors.is_empty() {
99	        return RunResult::Error(errors.join("\n"));
100	    }
101	
102	    let pairs = find_duplicate_pairs(
103	        &functions,
104	        config.threshold,
105	        config.min_lines,
106	        config.min_nodes,
107	    );
108	
109	    if pairs.is_empty() {
110	        RunResult::Clean
111	    } else {
112	        RunResult::Duplicates(pairs)
113	    }
114	}
