116	fn collect_all_functions(
117	    paths: &[String],
118	    exclude_set: &GlobSet,
119	) -> (Vec<FunctionInfo>, Vec<String>) {
120	    let mut functions: Vec<FunctionInfo> = Vec::new();
121	    let mut errors: Vec<String> = Vec::new();
122	    for path_str in paths {
123	        let path = Path::new(path_str);
124	        if !path.exists() {
125	            errors.push(format!("path does not exist: {}", path_str));
126	        } else {
127	            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
128	        }
129	    }
130	    (functions, errors)
131	}
