133	fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
134	    let mut builder = GlobSetBuilder::new();
135	    for pat in patterns {
136	        builder.add(Glob::new(pat)?);
137	    }
138	    builder.build()
139	}
