141	fn is_rust_file(path: &Path) -> bool {
142	    path.extension().and_then(|e| e.to_str()) == Some("rs")
143	}
144	
145	fn collect_functions_from_path(
146	    path: &Path,
147	    exclude_set: &GlobSet,
148	    functions: &mut Vec<FunctionInfo>,
149	    errors: &mut Vec<String>,
150	) {
151	    if path.is_file() {
152	        collect_from_single_file(path, exclude_set, functions, errors);
153	    } else {
154	        collect_from_directory(path, exclude_set, functions, errors);
155	    }
156	}
157	
158	fn collect_from_single_file(
159	    path: &Path,
160	    exclude_set: &GlobSet,
161	    functions: &mut Vec<FunctionInfo>,
162	    errors: &mut Vec<String>,
163	) {
164	    if !should_skip(path, exclude_set) && is_rust_file(path) {
165	        process_file(path, functions, errors);
166	    }
167	}
168	
169	fn should_process_entry(e: &walkdir::DirEntry, exclude_set: &GlobSet) -> bool {
170	    let ep = e.path();
171	    !should_skip(ep, exclude_set) && e.file_type().is_file() && is_rust_file(ep)
172	}
173	
174	fn collect_from_directory(
175	    path: &Path,
176	    exclude_set: &GlobSet,
177	    functions: &mut Vec<FunctionInfo>,
178	    errors: &mut Vec<String>,
179	) {
180	    for entry in WalkDir::new(path).sort_by_file_name() {
181	        match entry {
182	            Ok(e) if should_process_entry(&e, exclude_set) => {
183	                process_file(e.path(), functions, errors);
184	            }
185	            Ok(_) => {}
186	            Err(err) => {
187	                errors.push(format!("walk error: {}", err));
188	            }
189	        }
190	    }
191	}
192	
193	fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
194	    if exclude_set.is_empty() {
195	        return false;
196	    }
197	    exclude_set.is_match(path)
198	}
199	
200	fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
201	    let source = match std::fs::read_to_string(path) {
202	        Ok(s) => s,
203	        Err(e) => {
204	            errors.push(format!("cannot read {}: {}", path.display(), e));
205	            return;
206	        }
207	    };
208	
209	    match parse_source_tree(&source) {
210	        Ok(tree) => {
211	            let file_str = path.to_string_lossy().to_string();
212	            extract_functions(tree.root_node(), &source, &file_str, functions);
213	        }
214	        Err(msg) => {
215	            errors.push(format!("{} in {}", msg, path.display()));
216	        }
217	    }
218	}
