220	fn jaccard(a: &[u64], b: &[u64]) -> f64 {
221	    if a.is_empty() && b.is_empty() {
222	        return 1.0;
223	    }
224	    let set_a: HashSet<u64> = a.iter().copied().collect();
225	    let set_b: HashSet<u64> = b.iter().copied().collect();
226	    let intersection = set_a.intersection(&set_b).count();
227	    let union = set_a.union(&set_b).count();
228	    if union == 0 {
229	        return 0.0;
230	    }
231	    intersection as f64 / union as f64
232	}
