238	fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
239	    let (left, right) = order_endpoints(a, b);
240	    DuplicatePair {
241	        score,
242	        left: PairEndpoint {
243	            file: left.file.clone(),
244	            start_line: left.start_line,
245	            end_line: left.end_line,
246	            nodes: left.node_hashes.len(),
247	        },
248	        right: PairEndpoint {
249	            file: right.file.clone(),
250	            start_line: right.start_line,
251	            end_line: right.end_line,
252	            nodes: right.node_hashes.len(),
253	        },
254	    }
255	}
256	
257	fn is_same_location(a: &FunctionInfo, b: &FunctionInfo) -> bool {
258	    a.file == b.file && a.start_line == b.start_line
259	}
260	
261	fn find_duplicate_pairs(
262	    functions: &[FunctionInfo],
263	    threshold: f64,
264	    min_lines: usize,
265	    min_nodes: usize,
266	) -> Vec<DuplicatePair> {
267	    let candidates: Vec<&FunctionInfo> = functions
268	        .iter()
269	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
270	        .collect();
271	
272	    let mut pairs: Vec<DuplicatePair> = Vec::new();
273	
274	    for i in 0..candidates.len() {
275	        for j in (i + 1)..candidates.len() {
276	            let a = candidates[i];
277	            let b = candidates[j];
278	            if is_same_location(a, b) {
279	                continue;
280	            }
281	            let score = jaccard(&a.node_hashes, &b.node_hashes);
282	            if score >= threshold {
283	                pairs.push(make_pair(a, b, score));
284	            }
285	        }
286	    }
287	
288	    pairs.sort_by(|a, b| {
289	        b.score
290	            .partial_cmp(&a.score)
291	            .unwrap_or(std::cmp::Ordering::Equal)
292	            .then_with(|| a.left.file.cmp(&b.left.file))
293	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
294	            .then_with(|| a.right.file.cmp(&b.right.file))
295	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
296	    });
297	
298	    pairs
299	}
300	
301	fn order_endpoints<'a>(
302	    a: &'a FunctionInfo,
303	    b: &'a FunctionInfo,
304	) -> (&'a FunctionInfo, &'a FunctionInfo) {
305	    let cmp = a
306	        .file
307	        .cmp(&b.file)
308	        .then_with(|| a.start_line.cmp(&b.start_line));
309	    if cmp == std::cmp::Ordering::Greater {
310	        (b, a)
311	    } else {
312	        (a, b)
313	    }
314	}
