316	pub fn format_text(pairs: &[DuplicatePair]) -> String {
317	    let mut out = String::new();
318	    for p in pairs {
319	        out.push_str(&format!("DUPLICATE score={:.4}\n", p.score));
320	        out.push_str(&format!(
321	            "  {}:{}-{}\n",
322	            p.left.file, p.left.start_line, p.left.end_line
323	        ));
324	        out.push_str(&format!(
325	            "  {}:{}-{}  ({} nodes / {} nodes)\n",
326	            p.right.file, p.right.start_line, p.right.end_line, p.left.nodes, p.right.nodes
327	        ));
328	    }
329	    out
330	}
