336	pub fn collect_rust_files(paths: &[String]) -> Vec<PathBuf> {
337	    let mut files = Vec::new();
338	    for p in paths {
339	        let path = Path::new(p);
340	        if path.is_file() {
341	            files.push(path.to_path_buf());
342	        } else {
343	            for entry in WalkDir::new(path).sort_by_file_name().into_iter().flatten() {
344	                if entry.file_type().is_file()
345	                    && entry.path().extension().and_then(|x| x.to_str()) == Some("rs")
346	                {
347	                    files.push(entry.path().to_path_buf());
348	                }
349	            }
350	        }
351	    }
352	    files
353	}
