87	pub fn run(paths: &[String], config: &Config) -> RunResult {
88	    let exclude_set = match build_glob_set(&config.excludes) {
89	        Ok(gs) => gs,
90	        Err(e) => return RunResult::Error(format!("invalid exclude glob: {}", e)),
91	    };
92	
93	    let (functions, errors) = collect_all_functions(paths, &exclude_set);
94	
95	    if !errors.is_empty() {
96	        return RunResult::Error(errors.join("\n"));
97	    }
98	
99	    let pairs = find_duplicate_pairs(
100	        &functions,
101	        config.threshold,
102	        config.min_lines,
103	        config.min_nodes,
104	    );
105	
106	    if pairs.is_empty() {
107	        RunResult::Clean
108	    } else {
109	        RunResult::Duplicates(pairs)
110	    }
111	}
