113	fn collect_all_functions(
114	    paths: &[String],
115	    exclude_set: &GlobSet,
116	) -> (Vec<FunctionInfo>, Vec<String>) {
117	    let mut functions: Vec<FunctionInfo> = Vec::new();
118	    let mut errors: Vec<String> = Vec::new();
119	    for path_str in paths {
120	        let path = Path::new(path_str);
121	        if !path.exists() {
122	            errors.push(format!("path does not exist: {}", path_str));
123	        } else {
124	            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
125	        }
126	    }
127	    (functions, errors)
128	}
129	
130	fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
131	    let mut builder = GlobSetBuilder::new();
132	    for pat in patterns {
133	        builder.add(Glob::new(pat)?);
134	    }
135	    builder.build()
136	}
