138	fn is_rust_file(path: &Path) -> bool {
139	    path.extension().and_then(|e| e.to_str()) == Some("rs")
140	}
141	
142	fn collect_functions_from_path(
143	    path: &Path,
144	    exclude_set: &GlobSet,
145	    functions: &mut Vec<FunctionInfo>,
146	    errors: &mut Vec<String>,
147	) {
148	    if path.is_file() {
149	        collect_from_single_file(path, exclude_set, functions, errors);
150	    } else {
151	        collect_from_directory(path, exclude_set, functions, errors);
152	    }
153	}
154	
155	fn collect_from_single_file(
156	    path: &Path,
157	    exclude_set: &GlobSet,
158	    functions: &mut Vec<FunctionInfo>,
159	    errors: &mut Vec<String>,
160	) {
161	    if !should_skip(path, exclude_set) && is_rust_file(path) {
162	        process_file(path, functions, errors);
163	    }
164	}
165	
166	fn should_process_entry(e: &walkdir::DirEntry, exclude_set: &GlobSet) -> bool {
167	    let ep = e.path();
168	    !should_skip(ep, exclude_set) && e.file_type().is_file() && is_rust_file(ep)
169	}
170	
171	fn collect_from_directory(
172	    path: &Path,
173	    exclude_set: &GlobSet,
174	    functions: &mut Vec<FunctionInfo>,
175	    errors: &mut Vec<String>,
176	) {
177	    for entry in WalkDir::new(path).sort_by_file_name() {
178	        match entry {
179	            Ok(e) if should_process_entry(&e, exclude_set) => {
180	                process_file(e.path(), functions, errors);
181	            }
182	            Ok(_) => {}
183	            Err(err) => {
184	                errors.push(format!("walk error: {}", err));
185	            }
186	        }
187	    }
188	}
189	
190	fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
191	    if exclude_set.is_empty() {
192	        return false;
193	    }
194	    exclude_set.is_match(path)
195	}
196	
197	fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
198	    let source = match std::fs::read_to_string(path) {
199	        Ok(s) => s,
200	        Err(e) => {
201	            errors.push(format!("cannot read {}: {}", path.display(), e));
202	            return;
203	        }
204	    };
205	
206	    match parse_source_tree(&source) {
207	        Ok(tree) => {
208	            let file_str = path.to_string_lossy().to_string();
209	            extract_functions(tree.root_node(), &source, &file_str, functions);
210	        }
211	        Err(msg) => {
212	            errors.push(format!("{} in {}", msg, path.display()));
213	        }
214	    }
215	}
