217	fn jaccard(a: &[u64], b: &[u64]) -> f64 {
218	    if a.is_empty() && b.is_empty() {
219	        return 1.0;
220	    }
221	    let set_a: HashSet<u64> = a.iter().copied().collect();
222	    let set_b: HashSet<u64> = b.iter().copied().collect();
223	    let intersection = set_a.intersection(&set_b).count();
224	    let union = set_a.union(&set_b).count();
225	    if union == 0 {
226	        return 0.0;
227	    }
228	    intersection as f64 / union as f64
229	}
