231	fn source_lines(fi: &FunctionInfo) -> usize {
232	    fi.end_line.saturating_sub(fi.start_line) + 1
233	}
234	
235	fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
236	    let (left, right) = order_endpoints(a, b);
237	    DuplicatePair {
238	        score,
239	        left: PairEndpoint {
240	            file: left.file.clone(),
241	            start_line: left.start_line,
242	            end_line: left.end_line,
243	            nodes: left.node_hashes.len(),
244	        },
245	        right: PairEndpoint {
246	            file: right.file.clone(),
247	            start_line: right.start_line,
248	            end_line: right.end_line,
249	            nodes: right.node_hashes.len(),
250	        },
251	    }
252	}
253	
254	fn is_same_location(a: &FunctionInfo, b: &FunctionInfo) -> bool {
255	    a.file == b.file && a.start_line == b.start_line
256	}
257	
258	fn find_duplicate_pairs(
259	    functions: &[FunctionInfo],
260	    threshold: f64,
261	    min_lines: usize,
262	    min_nodes: usize,
263	) -> Vec<DuplicatePair> {
264	    let candidates: Vec<&FunctionInfo> = functions
265	        .iter()
266	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
267	        .collect();
268	
269	    let mut pairs: Vec<DuplicatePair> = Vec::new();
270	
271	    for i in 0..candidates.len() {
272	        for j in (i + 1)..candidates.len() {
273	            let a = candidates[i];
274	            let b = candidates[j];
275	            if is_same_location(a, b) {
276	                continue;
277	            }
278	            let score = jaccard(&a.node_hashes, &b.node_hashes);
279	            if score >= threshold {
280	                pairs.push(make_pair(a, b, score));
281	            }
282	        }
283	    }
284	
285	    pairs.sort_by(|a, b| {
286	        b.score
287	            .partial_cmp(&a.score)
288	            .unwrap_or(std::cmp::Ordering::Equal)
289	            .then_with(|| a.left.file.cmp(&b.left.file))
290	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
291	            .then_with(|| a.right.file.cmp(&b.right.file))
292	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
293	    });
294	
295	    pairs
296	}
297	
298	fn order_endpoints<'a>(
299	    a: &'a FunctionInfo,
300	    b: &'a FunctionInfo,
301	) -> (&'a FunctionInfo, &'a FunctionInfo) {
302	    let cmp = a
303	        .file
304	        .cmp(&b.file)
305	        .then_with(|| a.start_line.cmp(&b.start_line));
306	    if cmp == std::cmp::Ordering::Greater {
307	        (b, a)
308	    } else {
309	        (a, b)
310	    }
311	}
