313	pub fn format_text(pairs: &[DuplicatePair]) -> String {
314	    let mut out = String::new();
315	    for p in pairs {
316	        out.push_str(&format!("DUPLICATE score={:.4}\n", p.score));
317	        out.push_str(&format!(
318	            "  {}:{}-{}\n",
319	            p.left.file, p.left.start_line, p.left.end_line
320	        ));
321	        out.push_str(&format!(
322	            "  {}:{}-{}  ({} nodes / {} nodes)\n",
323	            p.right.file, p.right.start_line, p.right.end_line, p.left.nodes, p.right.nodes
324	        ));
325	    }
326	    out
327	}
