333	pub fn collect_rust_files(paths: &[String]) -> Vec<PathBuf> {
334	    let mut files = Vec::new();
335	    for p in paths {
336	        let path = Path::new(p);
337	        if path.is_file() {
338	            files.push(path.to_path_buf());
339	        } else {
340	            for entry in WalkDir::new(path).sort_by_file_name().into_iter().flatten() {
341	                if entry.file_type().is_file()
342	                    && entry.path().extension().and_then(|x| x.to_str()) == Some("rs")
343	                {
344	                    files.push(entry.path().to_path_buf());
345	                }
346	            }
347	        }
348	    }
349	    files
350	}
